  ('social-worker-moex-07230', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會團體工作的運作在團體的組成過程中，團體成員的選取以最能在團體中受益的人應被選為成員為原 則，因此選取團體成員必須同時注意背景和行為因素。下列那一種團體的運作在團體成員選取時，團體 成員的年齡差異不能太大，因為他們的成熟度與興趣的變化很大，會影響團體運作的效果？', '["老人團體", "兒童團體", "中年團體", "壯年團體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
