  ('social-worker-moex-07235', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '2005 年行政院提出「臺灣健康社區六星計畫」並提出六大面向作為社區發展的目標，下列那一個照顧服 務的推出即是在此背景下形成？', '["護理之家", "居家護理", "老人安養機構", "社區照顧關懷據點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
